import json

import yaml

from prompty.model import LlmStartPayload


def test_load_json_llmstartpayload():
    json_data = r"""
    {
      "provider": "openai",
      "modelId": "gpt-4o-mini",
      "messageCount": 4,
      "attempt": 0
    }
    """
    data = json.loads(json_data, strict=False)
    instance = LlmStartPayload.load(data)
    assert instance is not None
    assert instance.provider == "openai"
    assert instance.model_id == "gpt-4o-mini"
    assert instance.message_count == 4
    assert instance.attempt == 0


