def test_roundtrip_json_llmstartpayload():
    """Test that load -> save -> load produces equivalent data."""
    json_data = r"""
    {
      "provider": "openai",
      "modelId": "gpt-4o-mini",
      "messageCount": 4,
      "attempt": 0
    }
    """
    original_data = json.loads(json_data, strict=False)
    instance = LlmStartPayload.load(original_data)
    saved_data = instance.save()
    reloaded = LlmStartPayload.load(saved_data)
    assert reloaded is not None
    assert reloaded.provider == "openai"
    assert reloaded.model_id == "gpt-4o-mini"
    assert reloaded.message_count == 4
    assert reloaded.attempt == 0


